## 六、Java 完整实现

```java
import java.util.HashMap;
import java.util.Map;

public class LRUCache {

    /** 双向链表节点 */
    private static class Node {
        int key;
        int value;
        Node prev;
        Node next;

        Node() {}
        Node(int key, int value) {
            this.key = key;
            this.value = value;
        }
    }

    private final int capacity;
    private final Map<Integer, Node> cache;
    private final Node head;  // dummy head
    private final Node tail;  // dummy tail

    public LRUCache(int capacity) {
        this.capacity = capacity;
        this.cache = new HashMap<>();
        this.head = new Node();
        this.tail = new Node();
        head.next = tail;
        tail.prev = head;
    }

    /** 从链表中删除节点 — O(1) */
    private void remove(Node node) {
        node.prev.next = node.next;
        node.next.prev = node.prev;
    }

    /** 在 head 后面插入节点 — O(1) */
    private void addToHead(Node node) {
        node.next = head.next;
        node.prev = head;
        head.next.prev = node;
        head.next = node;
    }

    /** 把已有节点移到头部 — O(1) */
    private void moveToHead(Node node) {
        remove(node);
        addToHead(node);
    }

    /** 删除尾部节点（最久未使用），返回被删除的节点 — O(1) */
    private Node removeTail() {
        Node lru = tail.prev;
        remove(lru);
        return lru;
    }

    /** O(1) */
    public int get(int key) {
        Node node = cache.get(key);
        if (node == null) {
            return -1;
        }
        moveToHead(node);
        return node.value;
    }

    /** O(1) */
    public void put(int key, int value) {
        Node node = cache.get(key);
        if (node != null) {
            // key存在：更新 + 移到头部
            node.value = value;
            moveToHead(node);
        } else {
            // key不存在：新建节点
            Node newNode = new Node(key, value);
            cache.put(key, newNode);
            addToHead(newNode);
            if (cache.size() > capacity) {
                // 淘汰尾部
                Node lru = removeTail();
                cache.remove(lru.key);
            }
        }
    }

    // ========== 测试 ==========
    public static void main(String[] args) {
        LRUCache lru = new LRUCache(2);
        lru.put(1, 10);
        lru.put(2, 20);
        System.out.println(lru.get(1));   // 10
        lru.put(3, 30);                    // 淘汰2
        System.out.println(lru.get(2));   // -1
        System.out.println(lru.get(3));   // 30
        lru.put(4, 40);                    // 淘汰1
        System.out.println(lru.get(1));   // -1
        System.out.println(lru.get(3));   // 30
        System.out.println(lru.get(4));   // 40
    }
}
```

### Java 速写版（使用 LinkedHashMap）

```java
import java.util.LinkedHashMap;
import java.util.Map;

public class LRUCacheSimple extends LinkedHashMap<Integer, Integer> {
    private final int capacity;

    public LRUCacheSimple(int capacity) {
        super(capacity, 0.75f, true);  // accessOrder=true 是关键
        this.capacity = capacity;
    }

    public int get(int key) {
        return super.getOrDefault(key, -1);
    }

    public void put(int key, int value) {
        super.put(key, value);
    }

    @Override
    protected boolean removeEldestEntry(Map.Entry<Integer, Integer> eldest) {
        return size() > capacity;  // 超容量时自动淘汰最老的
    }
}
```

